def __eq__(self, other):
    # Needed for @total_ordering
    if isinstance(other, Field):
        return (
            self.creation_counter == other.creation_counter and
            self.model == other.model
        )
    return NotImplemented

def __lt__(self, other):
    # This is needed because bisect does not take a comparison function.
    # Order by creation_counter first, then by model to avoid breaking
    # existing ordering while fixing the equality issue with inherited
    # fields from abstract models.
    if isinstance(other, Field):
        if self.creation_counter != other.creation_counter:
            return self.creation_counter < other.creation_counter
        # If creation_counter is the same, order by model.
        # Use a sortable representation of the model for consistent ordering.
        self_model = self.model
        other_model = other.model
        if self_model == other_model:
            return False
        # Handle None models (fields not yet attached to a model)
        if self_model is None:
            return True
        if other_model is None:
            return False
        # Compare using model's label (app_label.model_name)
        return (
            (self_model._meta.label_lower) <
            (other_model._meta.label_lower)
        )
    return NotImplemented

def __hash__(self):
    return hash((self.creation_counter, self.model))

